        struct ifnet *ifp;
        struct epoch_tracker et;

        while (1) {
            NET_EPOCH_ENTER(et);
            CK_STAILQ_FOREACH(ifp, &V_ifnet, if_link) {
                if (ifp->if_home_vnet != ifp->if_vnet)
                    break;
            }
            NET_EPOCH_EXIT(et);
            if (ifp == NULL)
                  break;
            if_vmove(ifp, ifp->if_home_vnet);
        }
